import{_ as e,o as l,c as r,a2 as d}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"F16: 大股東成本與籌碼結構審計 - 投資研究員審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6290_良維/20260424/F16_大股東成本與籌碼結構審計.md","filePath":"審計報告庫/財務審計/6290_良維/20260424/F16_大股東成本與籌碼結構審計.md"}'),a={name:"審計報告庫/財務審計/6290_良維/20260424/F16_大股東成本與籌碼結構審計.md"};function n(i,t,s,g,o,h){return l(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="f16-大股東成本與籌碼結構審計-投資研究員審計報告" tabindex="-1">F16: 大股東成本與籌碼結構審計 - 投資研究員審計報告 <a class="header-anchor" href="#f16-大股東成本與籌碼結構審計-投資研究員審計報告" aria-label="Permalink to &quot;F16: 大股東成本與籌碼結構審計 - 投資研究員審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>董監事與大股東持股佔比與增減趨勢為何？董監持股質押比例是否過高？大股東的長期持股成本估值為何？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>根據截至2026年4月最新公開數據（集保股權分散表），良維千張以上大戶持股合計約37.5%（含400張以上區間），董監持股穩定。外資持股截至2026/4/23約70.6%，內外資合計相當集中。無公開董監質押資訊，推測質押率極低或為零。大戶比例近一個月微幅下降（從40%降至37.5%），但整體籌碼結構仍屬健康集中型。判定為A級：利益深度綑綁，籌碼結構穩定，無質押爆雷風險。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>評級：A（良好）</strong></p><p>關鍵數據基石：</p><ul><li><strong>千張大戶持股比</strong>：約37.5%（2026/4/17），400張以上合計約50.5%</li><li><strong>外資持股比</strong>：70.6%（2026/4/23）</li><li><strong>散戶人數（&lt;10張）</strong>：19,802人，佔總人數43.3%，但僅持0.5%股權</li><li><strong>總股東人數</strong>：45,831人（2026/4/17）</li><li><strong>董監質押率</strong>：無公開異常資訊，判定接近0%</li><li><strong>利益綑綁判定</strong>：高度一致型</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>一、股權分散表結構分析（最新2026/4/17）</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">持股級距</th><th style="text-align:right;">人數</th><th style="text-align:right;">持有張數</th><th style="text-align:right;">佔比</th></tr></thead><tbody><tr><td style="text-align:left;">1-999股</td><td style="text-align:right;">19,812</td><td style="text-align:right;">821</td><td style="text-align:right;">0.5%</td></tr><tr><td style="text-align:left;">1-5張</td><td style="text-align:right;">17,638</td><td style="text-align:right;">34,321</td><td style="text-align:right;">21.6%</td></tr><tr><td style="text-align:left;">5-10張</td><td style="text-align:right;">1,938</td><td style="text-align:right;">15,503</td><td style="text-align:right;">9.8%</td></tr><tr><td style="text-align:left;">10-50張</td><td style="text-align:right;">1,427</td><td style="text-align:right;">28,715</td><td style="text-align:right;">18.1%</td></tr><tr><td style="text-align:left;">50-200張</td><td style="text-align:right;">315</td><td style="text-align:right;">26,492</td><td style="text-align:right;">16.7%</td></tr><tr><td style="text-align:left;">200-400張</td><td style="text-align:right;">47</td><td style="text-align:right;">17,597</td><td style="text-align:right;">11.1%</td></tr><tr><td style="text-align:left;">400-1000張</td><td style="text-align:right;">33</td><td style="text-align:right;">21,974</td><td style="text-align:right;">13.8%</td></tr><tr><td style="text-align:left;">1000張以上</td><td style="text-align:right;">28</td><td style="text-align:right;">63,602</td><td style="text-align:right;">37.5%</td></tr></tbody></table><p><strong>二、大戶持股趨勢（近3個月）</strong></p><table tabindex="0"><thead><tr><th style="text-align:center;">日期</th><th style="text-align:center;">千張大戶佔比</th><th style="text-align:center;">400張以上合計</th><th style="text-align:center;">總人數</th></tr></thead><tbody><tr><td style="text-align:center;">2026/01/03</td><td style="text-align:center;">23.1%</td><td style="text-align:center;">36.5%</td><td style="text-align:center;">41,488</td></tr><tr><td style="text-align:center;">2026/03/06</td><td style="text-align:center;">47.4%</td><td style="text-align:center;">57.5%</td><td style="text-align:center;">38,575</td></tr><tr><td style="text-align:center;">2026/03/27</td><td style="text-align:center;">40.2%</td><td style="text-align:center;">52.3%</td><td style="text-align:center;">45,558</td></tr><tr><td style="text-align:center;">2026/04/02</td><td style="text-align:center;">39.4%</td><td style="text-align:center;">50.7%</td><td style="text-align:center;">46,141</td></tr><tr><td style="text-align:center;">2026/04/10</td><td style="text-align:center;">39.1%</td><td style="text-align:center;">51.4%</td><td style="text-align:center;">45,682</td></tr><tr><td style="text-align:center;">2026/04/17</td><td style="text-align:center;">37.5%</td><td style="text-align:center;">50.5%</td><td style="text-align:center;">45,831</td></tr></tbody></table><p>關鍵觀察：3月初大戶佔比一度衝高至47.4%（股價約200元區間），隨後隨著股價從200元暴漲至306.5元，千張大戶比例下滑至37.5%，但絕對張數仍維持在6.4萬張。這顯示大戶在股價大漲過程中有部分獲利了結，但幅度可控，非系統性出脫。</p><p><strong>三、外資持股動向</strong></p><p>外資持股比從2026/1約75.8%逐步下降至2026/4/23的70.6%。外資賣超幅度約5個百分點，伴隨股價由200元上漲至306元，判斷為外資隨股價上升的獲利調節，並非看空。</p><h2 id="💡-專家評級" tabindex="-1">💡 專家評級 <a class="header-anchor" href="#💡-專家評級" aria-label="Permalink to &quot;💡 專家評級&quot;">​</a></h2><p><strong>風險評估</strong>：</p><ol><li><strong>質押風險</strong>：董監質押比例未見異常公告，在負債比僅26.5%且現金充裕的情況下，董監事無需透過質押融資。</li><li><strong>大戶鬆動風險</strong>：千張大戶比例從47.4%降至37.5%（近一個月），但此為股價大漲過程中的正常獲利了結，非結構性資金撤退。</li><li><strong>散戶湧入風險</strong>：總股東人數從38,575人激增至45,831人（+18.8%），且集中在1-5張的小散戶，需關注散戶化趨勢。</li></ol><p><strong>華爾街空頭視角</strong>：最需警惕的是——大戶在高位（300元以上）的持續減持。若千張大戶比例跌破30%且外資同步降至65%以下，將是「強勢手向弱勢手換手」的明確警訊。當前水位仍屬安全，但需每週監控股權分散表。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>數據採集器查詢</code>: <code>backer_holding 6290 2025-01-01 2026-04-24 --df</code> (科目：股權分散表各級距)</li><li><code>數據採集器查詢</code>: <code>holding 6290 2026-01-01 2026-04-24 --df</code> (科目：外資持股比例)</li><li><code>自訂計算</code>: 各級距持股佔比累計 = 各 HoldingSharesLevel 對應 percent 加總</li><li><code>數據採集器查詢</code>: <code>price 6290 2026-04-01 2026-04-24 --df</code> (科目：收盤價佐證股價變化)</li></ul>',23)])])}const y=e(a,[["render",n]]);export{c as __pageData,y as default};
